const userId = $('Get Active Users').item.json.user_id;
const indicators = $('Get User Indicators').all().map(i => i.json);

// Group by company + indicator_type + similar reason
const patterns = {};
for (const ind of indicators) {
  // Simple grouping: company + type + first 50 chars of reason (in production, use LLM semantic clustering)
  const reasonKey = ind.reason.substring(0, 50).toLowerCase().replace(/[^a-z0-9 ]/g, '');
  const key = `${ind.company_name}__${ind.indicator_type}__${reasonKey}`;

  if (!patterns[key]) {
    patterns[key] = {
      user_id: userId,
      pattern_type: ind.indicator_type,
      company_name: ind.company_name,
      company_id: ind.company_id,
      description: ind.reason,
      frequency: 0,
      indicator_ids: [],
      sentiments: [],
      first_seen: ind.detected_at,
      last_seen: ind.detected_at
    };
  }

  patterns[key].frequency++;
  patterns[key].indicator_ids.push(ind.id);
  patterns[key].sentiments.push(ind.sentiment_score);

  if (new Date(ind.detected_at) < new Date(patterns[key].first_seen)) {
    patterns[key].first_seen = ind.detected_at;
  }
  if (new Date(ind.detected_at) > new Date(patterns[key].last_seen)) {
    patterns[key].last_seen = ind.detected_at;
  }
}

// Compute trend (simple: more recent = rising)
const results = Object.values(patterns).map(p => {
  const avgSentiment = p.sentiments.reduce((a, b) => a + b, 0) / p.sentiments.length;
  const midpoint = new Date(Date.now() - 45 * 24 * 60 * 60 * 1000);
  const recentCount = p.indicator_ids.filter((_, idx) => {
    // Indicators are sorted DESC so index 0 is most recent
    return idx < p.indicator_ids.length / 2;
  }).length;
  const olderCount = p.indicator_ids.length - recentCount;

  let trend = 'stable';
  if (recentCount > olderCount * 1.5) trend = 'rising';
  else if (olderCount > recentCount * 1.5) trend = 'falling';

  const confidence = Math.min(1, 0.3 + (p.frequency * 0.1));

  return {
    user_id: p.user_id,
    pattern_type: p.pattern_type,
    company_name: p.company_name,
    company_id: p.company_id,
    description: p.description,
    frequency: p.frequency,
    trend: trend,
    confidence: Math.round(confidence * 100) / 100,
    first_seen: p.first_seen,
    last_seen: p.last_seen,
    indicator_ids: p.indicator_ids
  };
});

// Only keep patterns with frequency >= 2
return results.filter(r => r.frequency >= 2).map(r => ({ json: r }));
